const body = $input.first().json.body || $input.first().json;
const db06_id = (body.db06_id || body.id || '').toString().replace(/-/g, '');
if (!db06_id) throw new Error('missing db06_id');
return [{ json: { db06_id } }];

const p=$input.first().json;
const T=['е°ҚжҮүжҸҗжЎҲ','е°ҚжҮүз®ЎиҖғ','е°ҚжҮүй …зӣ®','е°ҚжҮүеҚ”дҪң','е°ҚжҮүе…§е®№','е°ҚжҮүеә«еӯҳ','е°ҚжҮүе°ҚиұЎ','е°ҚжҮүжЁҷзұӨ','е°ҚжҮүең°й»һ','е°ҚжҮүжҸҗдҫӣе°ҚиұЎ'];
let tid='',trel='';
for(const r of T){const a=p.properties[r]?.relation||[];if(a.length){tid=(a[0].id||'').replace(/-/g,'');trel=r;break;}}
return [{json:{db06_id:p.id.replace(/-/g,''),ai_mode:p.properties['aiжЁЎејҸ']?.select?.name||'жӘўж ё',exec_idea_db06:(p.properties['еҹ·иЎҢж§Ӣжғі']?.rich_text||[]).map(t=>t.plain_text).join(''),db06_check_note:(p.properties['жӘўж ёеӮҷиЁ»']?.rich_text||[]).map(t=>t.plain_text).join(''),db05_id:tid,target_rel:trel,sort_num:p.properties['жҺ’еәҸ']?.number}}];

const c=$input.first().json;
const system='дҪ жҳҜ makesense е—Ёе—Ёе®¶ж—Ҹзҡ„е—Ёе—ЁжӘўж ёгҖӮеҸӘеҒҡдёҖд»¶дәӢпјҡеҲӨж–·ж–ҮжЎҲеҜ«еҮәдҫҶзҡ„й ҒйқўжӯЈж–ҮпјҢжҳҜеҗҰе®ҢжҲҗдәҶеҹ·иЎҢж§ӢжғідәӨиҫҰзҡ„дәӢгҖӮйҖҗз« е°Қз…§пјҡеҹ·иЎҢж§ӢжғіиҰҒжұӮзҡ„з« зҜҖ/йҮҚй»һпјҢжӯЈж–ҮжңүжІ’жңүе°ҚжҮүеҜ«еҲ°гҖӮеҸӘеӣһеҗҲжі• JSONпјҡ{"иӘһж„Ҹе°ҚжҮү":"з¬ҰеҗҲ"жҲ–"жңүеҒҸйӣў","иӘӘжҳҺ":"дёҖе…©еҸҘпјҢеҒҸйӣўе°ұжҢҮеҮәе“ӘиЈЎжІ’е°ҚдёҠ"}';
const user='гҖҗеҹ·иЎҢж§ӢжғіпјҲдәӨиҫҰе…§е®№пјүгҖ‘
'+(c.exec_idea||'(з©ә)')+'

гҖҗж–ҮжЎҲеҜ«еҮәзҡ„й ҒйқўжӯЈж–ҮпјҲеүҚж®өзҜҖйҢ„пјүгҖ‘
'+(c.blockText||'(з©ә)')+'

еҲӨж–·жӯЈж–ҮжҳҜеҗҰе®ҢжҲҗеҹ·иЎҢж§ӢжғідәӨиҫҰзҡ„дәӢпјҢеӣһ JSONгҖӮ';
return [{json:{...c,system,user}}];

const resp=$input.first().json;
const c=$('жӘўж ёзӣӨй»һ').first().json;
const text=resp.content?.[0]?.text||'';
let sem; try{const m=text.match(/\{[\s\S]*\}/);sem=m?JSON.parse(m[0]):{};}catch(e){sem={};}
const semOK=(sem['иӘһж„Ҹе°ҚжҮү']||'').indexOf('з¬ҰеҗҲ')>=0;
const semNote=(sem['иӘӘжҳҺ']||'').toString();
const mk=b=>b?'вң“':'вҡ пёҸ';
const items=[['дјҒеҠғ',c.c1],['жҗңжҹҘ',c.c2],['еҲҶжһҗ',c.c3],['иҒҜжғі',c.c4],['ж–ҮжЎҲ',c.c5&&semOK]];
const allOK=items.every(x=>x[1])&&semOK;
const fails=[];
if(!c.c1)fails.push('дјҒеҠғ(еҹ·иЎҢж§ӢжғідёҚи¶і)');
if(!c.c2)fails.push('жҗңжҹҘ(з„ЎиіҮж–ҷеҸғиҖғ)');
if(!c.c3)fails.push('еҲҶжһҗ(иіҮж–ҷеҸғиҖғзјәе°ҚжҮүжЁҷзұӨ'+(c.refNoTag.length?'пјҡ'+c.refNoTag.slice(0,5).join('гҖҒ'):'')+')');
if(!c.c4)fails.push('иҒҜжғі(Xеј•з”ЁдёҚи¶і3зӯҶжҲ–жңӘи·Ё2DB)');
if(!c.c5)fails.push('ж–ҮжЎҲ(жӯЈж–ҮжҲ–зҷјдҪҲзӢҖж…ӢжңӘеҲ°дҪҚ)');
if(!semOK)fails.push('ж–ҮжЎҲиӘһж„ҸеҒҸйӣў');
const d=new Date();const tw=new Date(d.getTime()+8*3600*1000);
const ts=tw.getUTCFullYear()+'-'+String(tw.getUTCMonth()+1).padStart(2,'0')+'-'+String(tw.getUTCDate()).padStart(2,'0')+' '+String(tw.getUTCHours()).padStart(2,'0')+':'+String(tw.getUTCMinutes()).padStart(2,'0');
const checkLine='дјҒеҠғ '+mk(c.c1)+' / жҗңжҹҘ '+mk(c.c2)+' / еҲҶжһҗ '+mk(c.c3)+' / иҒҜжғі '+mk(c.c4)+' / ж–ҮжЎҲ '+mk(c.c5&&semOK);
const detail='жҗңжҹҘиіҮж–ҷеҸғиҖғ '+c.refCount+' зӯҶгҖҒXеј•з”Ёе…ұ '+c.xrefTotal+' зӯҶи·Ё '+c.xfWith+' йЎһгҖҒжӯЈж–Ү '+c.blockLen+' еӯ—гҖҒзҷјдҪҲзӢҖж…Ӣ='+(c.pubStatus||'(з©ә)');
const advice=allOK?'е…Ёй …йҖҡйҒҺпјҢеҸҜжЁҷе®ҢжҲҗ':('е»әиӯ°иЈңпјҡ'+fails.join('пјӣ'));
const execNote='в”Җв”Җ '+ts+' жӘўж ё в”Җв”Җ\nе·ҘдҪңе°ҚиұЎпјҡ'+c.target_name+'\nе®ҢжҲҗеәҰпјҡ'+checkLine+'\nиӘһж„Ҹе°ҚжҮүпјҡ'+(semOK?'з¬ҰеҗҲ':('жңүеҒҸйӣў вҖ” '+semNote))+'\nе»әиӯ°пјҡ'+advice;
const checkReport='в”Җв”Җ '+ts+' жӘўж ё в”Җв”Җ\n'+checkLine+'\n'+detail+'\nиӘһж„Ҹе°ҚжҮүпјҡ'+(semOK?'з¬ҰеҗҲ':('жңүеҒҸйӣў вҖ” '+semNote))+'\nе»әиӯ°пјҡ'+advice;
const tgtCheck=(checkReport+(c.tgt_check_note?('\n\n'+c.tgt_check_note):'')).slice(0,1990);
const db06Check=(checkReport+(c.db06_check_note?('\n\n'+c.db06_check_note):'')).slice(0,1990);
const usage=resp.usage||{};
const it=parseInt(usage.input_tokens||0),ot=parseInt(usage.output_tokens||0);
const cost=((it*0.8+ot*4)/1000000*32).toFixed(2);
return [{json:{target_id:c.target_id,db06_id:c.db06_id,target_name:c.target_name,
exec_note:execNote.slice(0,1990),check_report:checkReport,
tgt_check:tgtCheck,db06_check:db06Check,all_ok:allOK,usage_line:'йҖІ='+it+' еҮә='+ot+' жҲҗжң¬NT'+cost}}];

const baton=$('Parse DB06').first().json;
const target=$('Fetch target DB05').first().json;
const NHEAD={'Authorization':'Bearer '+$env.NOTION_INTEGRATION_TOKEN,'Notion-Version':'2022-06-28','Content-Type':'application/json'};
const norm=id=>(id||'').replace(/-/g,'');
const withTO=(p,ms)=>Promise.race([p,new Promise((_,r)=>setTimeout(()=>r(new Error('to')),ms))]);
const sleep=ms=>new Promise(r=>setTimeout(r,ms));
const getPage=async id=>{try{const r=await withTO(this.helpers.httpRequest({method:'GET',url:'https://api.notion.com/v1/pages/'+id,headers:NHEAD}),10000);return (typeof r==='string')?JSON.parse(r):r;}catch(e){return null;}};
const tp=target.properties||{};
const rt=k=>(tp[k]?.rich_text||[]).map(t=>t.plain_text).join('');
const target_id=norm(target.id);
const titleProp=Object.values(tp).find(v=>v&&v.type==='title');
const target_name=(titleProp?.title||[]).map(t=>t.plain_text).join('')||'(жңӘе‘ҪеҗҚ)';
const exec_idea=rt('еҹ·иЎҢж§Ӣжғі');
const theme=rt('дё»йЎҢеҗҚзЁұ'); const summary=rt('з°Ўд»Ӣж‘ҳиҰҒ');
const pubStatus=tp['зҷјдҪҲзӢҖж…Ӣ']?.status?.name||'';
const tgt_check_note=rt('жӘўж ёеӮҷиЁ»');
const XF=['жҸҗжЎҲеј•з”Ё','з®ЎиҖғеј•з”Ё','й …зӣ®еј•з”Ё','еҚ”дҪңеј•з”Ё','е…§е®№еј•з”Ё','жҳҺзҙ°еј•з”Ё','еә«еӯҳеј•з”Ё','е°ҚиұЎеј•з”Ё','ж—Ҙжңҹеј•з”Ё'];
let xfWith=0; let xrefIds=[];
for(const f of XF){const a=(tp[f]&&tp[f].relation)||[];if(a.length)xfWith++;for(const r of a)xrefIds.push(norm(r.id));}
xrefIds=[...new Set(xrefIds)];
const xrefTotal=xrefIds.length;
const DB06='3469ff25fdab83c98ff98107ee6a6a1c';
let refCount=0; const refNoTag=[];
const ids=xrefIds.slice(0,40);
for(let i=0;i<ids.length;i+=4){
  const part=await Promise.all(ids.slice(i,i+4).map(getPage));
  for(const pg of part){if(!pg)continue;
    if(norm((pg.parent||{}).database_id||'')!==DB06)continue;
    const mtype=pg.properties['жҳҺзҙ°йЎһеһӢ']?.select?.name||'';
    if(mtype==='иіҮж–ҷеҸғиҖғ'){refCount++;const tags=(pg.properties['е°ҚжҮүжЁҷзұӨ']?.relation||[]);if(!tags.length){const nm=(pg.properties['жҳҺзҙ°еҗҚзЁұ']?.title||[]).map(t=>t.plain_text).join('');refNoTag.push(nm||norm(pg.id).slice(0,8));}}
  }
  if(i+4<ids.length)await sleep(320);
}
let blockText='';
try{const b=await withTO(this.helpers.httpRequest({method:'GET',url:'https://api.notion.com/v1/blocks/'+target_id+'/children?page_size=100',headers:NHEAD}),12000);const bb=(typeof b==='string')?JSON.parse(b):b;for(const blk of (bb.results||[])){const t=blk[blk.type];if(t&&t.rich_text)blockText+=(t.rich_text.map(x=>x.plain_text).join(''))+'\n';}}catch(e){}
const c1=exec_idea.length>=30;
const c2=refCount>=1;
const c3=refCount>0&&refNoTag.length===0;
const c4=xrefTotal>=3&&xfWith>=2;
const c5=blockText.trim().length>50&&pubStatus==='еҫ…зҷјдҪҲ';
return [{json:{target_id,target_name,db06_id:baton.db06_id,ai_mode:baton.ai_mode,sort_num:baton.sort_num,
db06_check_note:baton.db06_check_note||'',tgt_check_note,
exec_idea,theme,summary,pubStatus,xfWith,xrefTotal,refCount,refNoTag,
blockText:blockText.slice(0,4000),blockLen:blockText.length,c1,c2,c3,c4,c5}}];

